 {"id":"bd-1gx6","title":"epoll reactor: Linux fallback for pre-5.1 kernels","description":"# epoll Reactor Implementation (Linux Fallback)

## Overview
Implements the Reactor trait using epoll for Linux systems without io_uring support
(kernels < 5.1 or systems where io_uring is disabled).

## Background
While io_uring is superior, not all Linux systems have it:
- Older kernels (CentOS 7, older Ubuntu LTS)
- Containers/VMs with restricted syscalls
- Embedded systems with custom kernels

epoll is the proven, stable fallback that works everywhere.

## Design

### EpollReactor Structure
```rust
pub struct EpollReactor {
    /// epoll file descriptor
    epfd: RawFd,
    /// eventfd for wake signal
    wake_fd: RawFd,
}

impl EpollReactor {
    pub fn new() -> io::Result<Self> {
        let epfd = unsafe { libc::epoll_create1(libc::EPOLL_CLOEXEC) };
        if epfd < 0 {
            return Err(io::Error::last_os_error());
        }

        let wake_fd = unsafe { libc::eventfd(0, libc::EFD_NONBLOCK | libc::EFD_CLOEXEC) };
        if wake_fd < 0 {
            unsafe { libc::close(epfd) };
            return Err(io::Error::last_os_error());
        }

        // Register wake_fd
        let mut event = libc::epoll_event {
            events: libc::EPOLLIN as u32,
            u64: WAKE_TOKEN as u64,
        };
        if unsafe { libc::epoll_ctl(epfd, libc::EPOLL_CTL_ADD, wake_fd, &mut event) } < 0 {
            return Err(io::Error::last_os_error());
        }

        Ok(Self { epfd, wake_fd })
    }
}
```

### Reactor Implementation
```rust
impl Reactor for EpollReactor {
    fn register(&self, fd: RawFd, token: usize, interest: Interest) -> io::Result<()> {
        let mut events = 0u32;
        if interest.readable {
            events |= libc::EPOLLIN as u32;
        }
        if interest.writable {
            events |= libc::EPOLLOUT as u32;
        }
        // Edge-triggered for efficiency
        events |= libc::EPOLLET as u32;

        let mut event = libc::epoll_event {
            events,
            u64: token as u64,
        };

        if unsafe { libc::epoll_ctl(self.epfd, libc::EPOLL_CTL_ADD, fd, &mut event) } < 0 {
            return Err(io::Error::last_os_error());
        }

        Ok(())
    }

    fn reregister(&self, fd: RawFd, token: usize, interest: Interest) -> io::Result<()> {
        let mut events = 0u32;
        if interest.readable { events |= libc::EPOLLIN as u32; }
        if interest.writable { events |= libc::EPOLLOUT as u32; }
        events |= libc::EPOLLET as u32;

        let mut event = libc::epoll_event { events, u64: token as u64 };

        if unsafe { libc::epoll_ctl(self.epfd, libc::EPOLL_CTL_MOD, fd, &mut event) } < 0 {
            return Err(io::Error::last_os_error());
        }

        Ok(())
    }

    fn deregister(&self, fd: RawFd) -> io::Result<()> {
        if unsafe { libc::epoll_ctl(self.epfd, libc::EPOLL_CTL_DEL, fd, std::ptr::null_mut()) } < 0 {
            return Err(io::Error::last_os_error());
        }
        Ok(())
    }

    fn poll(&self, events: &mut Events, timeout: Option<Duration>) -> io::Result<usize> {
        let timeout_ms = timeout.map_or(-1, |d| d.as_millis() as i32);

        let mut epoll_events = vec![unsafe { std::mem::zeroed::<libc::epoll_event>() }; events.capacity];

        let n = unsafe {
            libc::epoll_wait(
                self.epfd,
                epoll_events.as_mut_ptr(),
                epoll_events.len() as i32,
                timeout_ms,
            )
        };

        if n < 0 {
            let err = io::Error::last_os_error();
            if err.kind() == io::ErrorKind::Interrupted {
                return Ok(0);
            }
            return Err(err);
        }

        for i in 0..n as usize {
            let ev = &epoll_events[i];
            if ev.u64 == WAKE_TOKEN as u64 {
                // Consume wake event
                let mut buf = [0u8; 8];
                let _ = unsafe { libc::read(self.wake_fd, buf.as_mut_ptr() as *mut _, 8) };
                continue;
            }

            let ready = Interest {
                readable: ev.events & libc::EPOLLIN as u32 != 0,
                writable: ev.events & libc::EPOLLOUT as u32 != 0,
                error: ev.events & (libc::EPOLLERR | libc::EPOLLHUP) as u32 != 0,
            };
            events.push(Event { token: ev.u64 as usize, ready });
        }

        Ok(n as usize)
    }

    fn wake(&self) -> io::Result<()> {
        let val: u64 = 1;
        let _ = unsafe { libc::write(self.wake_fd, &val as *const _ as *const _, 8) };
        Ok(())
    }
}
```

## Automatic Selection
```rust
#[cfg(target_os = "linux")]
pub fn create_reactor() -> io::Result<Arc<dyn Reactor>> {
    // Check for io_uring support
    if cfg!(feature = "io-uring") && io_uring::is_available() {
        return Ok(Arc::new(IoUringReactor::new()?));
    }

    // Fall back to epoll
    Ok(Arc::new(EpollReactor::new()?))
}
```

